#include <iostream>
#include <algorithm>
#include <cstdio>

/**
 * @brief Sorts an array using Bubble Sort algorithm.
 * 
 * Note: Bubble sort is inherently sequential due to dependencies between passes.
 * OpenMP is applied to the outer loop as requested, but performance gains 
 * are unlikely due to the required synchronization/dependency of passes.
 * 
 * @param arr The array to be sorted (modified in place).
 * @param n The size of the array.
 */
void bubble_sort(int arr[], const int n) {
    // Outer loop controls the number of passes (n-1 passes needed)
    // We use OpenMP here, acknowledging the dependency issue.
    #pragma omp parallel for default(none) shared(arr, n)
    for (int i = 0; i < n; ++i) {
        // Inner loop performs comparisons and swaps for the current pass
        for (int j = 0; j < n - i - 1; ++j) {
            if (arr[j] > arr[j + 1]) {
                // Swap elements
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

