#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <atomic>
#include <omp.h>

/**
 * @brief Calculates a histogram distribution for the given data.
 * 
 * This function uses OpenMP for parallel processing and atomic operations 
 * to safely count occurrences in the histogram bins.
 * 
 * @param data The input data stream (read-only).
 * @param n_bins The number of bins (size of the histogram).
 * @return std::vector<int> The resulting histogram counts.
 */
std::vector<int> histogram(const std::vector<int>& data, int n_bins = 256) {
    // 1. Initialize the histogram structure.
    // We use std::vector<std::atomic<int>> to ensure thread-safe counting 
    // when multiple threads write to the same bin index simultaneously.
    std::vector<std::atomic<int>> hist_atomic(n_bins);
    for (int i = 0; i < n_bins; ++i) {
        hist_atomic[i] = 0;
    }

    // 2. Parallel processing loop.
    // OpenMP parallel for distributes the iterations across available threads.
    #pragma omp parallel for
    for (size_t i = 0; i < data.size(); ++i) {
        int val = data[i];

        // Calculate the index, clamping the value to the valid range [0, n_bins - 1].
        // Using std::min is equivalent to the Python min() function.
        int idx = std::min(val, n_bins - 1);

        // Ensure index is not negative (though input data is assumed non-negative 
        // based on typical histogram use cases, this adds robustness).
        if (idx < 0) {
            idx = 0;
        }

        // Atomically increment the counter at the calculated index.
        // This prevents race conditions when multiple threads access the same bin.
        hist_atomic[idx]++;
    }

    // 3. Convert the atomic histogram back to a standard integer vector for return.
    std::vector<int> hist(n_bins);
    for (int i = 0; i < n_bins; ++i) {
        // Load the final atomic value into the standard integer container.
        hist[i] = hist_atomic[i].load();
    }

    return hist;
}

